using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" → "$type".
            // Existing documents still have "Discriminator", so pin the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" → "Key".
            // Existing documents use "Blog|1" format, so opt back in to the legacy format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes defined via EF.
            // EF 9 now throws instead of silently ignoring. Remove HasIndex.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

    // Breaking change 4: EF 9 enables sync I/O on Cosmos by default=false.
    // SyncJob.cs uses .ToList() and .SaveChanges() — see SyncJob.cs fix.
}

